QActions.QAction:

using System;
using System.IO;
using System.Text;
using Skyline.DataMiner.Scripting;
using System.Linq;
using System.Globalization;
using System.Threading;

public class QAction
{
    static Random r = new Random();

    public static void Run(SLProtocol protocol) //Adds a new datapoint every time the timer rings
	{
        int InPattern = int.Parse(protocol.GetParameter(102).ToString(), CultureInfo.InvariantCulture);
        if (InPattern != 0)
        {
            protocol.SetParameter(102, 0);
            protocol.SetParameter(2, 10);
        }
        int remainingTimeInPattern= int.Parse(protocol.GetParameter(2).ToString(), CultureInfo.InvariantCulture);
        if (remainingTimeInPattern == 0)
        {
            double u1 = 1.0 - r.NextDouble(); //uniform(0,1] random doubles
            double u2 = 1.0 - r.NextDouble();
            double randStdNormal = Math.Sqrt(-2.0 * Math.Log(u1)) *
                         Math.Sin(2.0 * Math.PI * u2); //random normal(0,1)
            double randNormal =
                         635 + 2 * randStdNormal;
            protocol.SetParameter(1, randNormal);
        }
        else
        {
            protocol.SetParameter(2, --remainingTimeInPattern);
            protocol.SetParameter(1, 700);
        }
	}

}


using System;
using System.IO;
using System.Text;
using Skyline.DataMiner.Scripting;
using System.Linq;
using System.Globalization;
using System.Threading;

public class QAction
{
    public static void Run(SLProtocol protocol) //runs on startup
    {
        protocol.Log("QAction 2 is running");
        protocol.SetParameter(1,635);
        Thread.Sleep(2000);
        protocol.SetParameter(102, 1);
    }
}
